head.script:
// 수정 불가능 로직
//전역변수
scwin.login                     = $c.data.getMemInfo();
scwin.parentFrame               = $c.win.getParent();
scwin.pos_groupCode             = 0;
scwin.vUserHomeClsCd            = scwin.login.userHomeClsCd;
scwin.vSysAdminYn               = scwin.login.sysAdminYn;
// scwin.vEqCd                     = ""
scwin.vEqCd                     = scwin.parentFrame.scwin.eqCd == null ? "" : scwin.parentFrame.scwin.eqCd;
scwin.curDate                   = WebSquare.date.getCurrentServerDate();

//hidden
scwin.txt_clntNoValChk          = "";
scwin.txt_eqCd                  = "0";
scwin.txt_qryCond               = "0";
scwin.txt_sysCls                = "0";
scwin.txt_payIdx                = "";
scwin.txt_createYn              = "0";
scwin.txt_updateYn              = "0";
scwin.txt_rowCount              = "";
scwin.txt_saveType              = "";


//-------------------------------------------------------------------------
// 화면로딩시
//-------------------------------------------------------------------------
scwin.onpageload = function() {
    const codeOptions = [
        { grpCd : "ZZ205", compID : "gr_logisticsHeavyEquip:eqHomeClsCd" },
        { grpCd : "ZZ202", compID : "acb_eqClssCd", opt : {'range': '2,DS'} },
    ];
    $c.data.setCommonCode(codeOptions);

    acb_sysCls.setValue("LO")
};

scwin.onUdcCompleted = function() {

    scwin.f_ContentsDisable();
    acb_qryCond.setValue("2");
    scwin.txt_payIdx = 1;

    //부모에서도 파라미터로 해당 전역변수에 넣음.
    // if(scwin.vEqCd.trim()!= ""){
    //     lux_qryCond.Index = 1;
    //     ed_qryCntn.setValue(scwin.vEqCd);

    //     scwin.f_Retrieve();

    // }

    if(scwin.vSysAdminYn == "1" || scwin.vUserHomeClsCd =="DS"){
        $c.gus.cfDisableBtn([b_Cancel, btn_save]);
    }else{
        $c.gus.cfDisableAllBtn();
    }

    ed_qryCntn.focus();

};

//-------------------------------------------------------------------------
// 물류자차위수탁 장비 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function () {  

    scwin.txt_saveType = 2;  // 0:신규, 1:수정, 2:조회

    if(ed_qryCntn.getValue() == "" ) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_011.replace("%1", "검색어").replace("%2", "글자(숫자) 한(두)"));
        ed_qryCntn.focus();
        return false;
    }

    let vEqDelYn = "0";

    if(cbx_eqDelYn.getValue() == "1"){
        vEqDelYn = "1";
    }


    let condition = "?";
    condition += "sysCls=" + acb_sysCls.getValue()
            + "&qryCond=" + acb_qryCond.getValue()
            + "&qryCntn=" + ed_qryCntn.getValue()
            + "&eqDelYn=" + vEqDelYn;

    sbm_searchlogisticsHeavyEquip.action = "/cm.bc.eq.eqmgnt.cmd.RetrieveLogisticsHeavyEquipEquipmentListCMD.do" + condition; 
    $c.sbm.execute(sbm_searchlogisticsHeavyEquip);
    scwin.f_ContentsDisable();

    $c.gus.cfDisableBtn([b_Cancel, btn_save]);

}

//-------------------------------------------------------------------------
// 항목 Enable
//-------------------------------------------------------------------------
scwin.f_ContentsEnable = function () {

    $c.gus.cfEnableKeyData();

    // 링크 이미지 활성화
    $c.gus.cfEnableObj(logisEqPosWrkPl_search, true); //작업장조회 이미지
    $c.gus.cfEnableObj(drv1_search, true); // 정기사1 조회 이미지
    $c.gus.cfEnableObj(drv2_search, true); // 정기사2조회 이미지
    $c.gus.cfEnableObj(drv3_search, true); // 정기사3 조회 이미지
    $c.gus.cfEnableObj(ica_eqChgDt, true); // 장비변경일자 조회 이미지

    $c.gus.cfEnableObj(rd_eqDelYn, false); // 장비사용여부

    // cfEnableKeyData함수로 disable 안되는 공통udc cd 별도 관리
    $c.gus.cfEnableObj(ed_logisEqPosWrkPlCd, true);
    $c.gus.cfEnableObj(ed_drvEmpNo1, true);
    $c.gus.cfEnableObj(ed_drvEmpNo2, true);
    $c.gus.cfEnableObj(ed_drvEmpNo3, true);

}

//-------------------------------------------------------------------------
// 항목 Disable
//-------------------------------------------------------------------------
scwin.f_ContentsDisable = function () {


    $c.gus.cfDisableKeyData();

    // 링크 이미지 비활성화
    $c.gus.cfEnableObj(logisEqPosWrkPl_search, false); //작업장조회 이미지
    $c.gus.cfEnableObj(drv1_search, false); // 정기사1 조회 이미지
    $c.gus.cfEnableObj(drv2_search, false); // 정기사2조회 이미지
    $c.gus.cfEnableObj(drv3_search, false); // 정기사3 조회 이미지
    $c.gus.cfEnableObj(ica_eqChgDt, false); // 장비변경일자 조회 이미지
    $c.gus.cfEnableObj(ed_eqCd, false);  
    $c.gus.cfEnableObj(ed_eqKndNm, false);  
    $c.gus.cfEnableObj(ed_eqNrmNm, false);  
    $c.gus.cfEnableObj(ed_vehclNo, false);  
    $c.gus.cfEnableObj(ed_assgnLobranCd, false);  
    $c.gus.cfEnableObj(ed_assgnLobranNm, false);  
    $c.gus.cfEnableObj(ica_assgnDt, false);  
    $c.gus.cfEnableObj(ed_logisEqPosWrkPlNm, false);  
    $c.gus.cfEnableObj(ed_drvEmpNm1, false);  
    $c.gus.cfEnableObj(ed_drvEmpNm2, false);  
    $c.gus.cfEnableObj(ed_drvEmpNm3, false);  
    $c.gus.cfEnableObj(ed_regId, false);  
    $c.gus.cfEnableObj(ica_regDtm, false);  
    $c.gus.cfEnableObj(ed_modId, false);  
    $c.gus.cfEnableObj(ica_modDtm, false);

    // cfEnableKeyData함수로 disable 안되는 공통udc cd 별도 관리
    $c.gus.cfEnableObj(ed_logisEqPosWrkPlCd, false);
    $c.gus.cfEnableObj(ed_drvEmpNo1, false);
    $c.gus.cfEnableObj(ed_drvEmpNo2, false);
    $c.gus.cfEnableObj(ed_drvEmpNo3, false);

    $c.gus.cfEnableObj(rd_eqDelYn, false); // 장비사용여부

}

//-------------------------------------------------------------------------
// 수정
//-------------------------------------------------------------------------
scwin.f_Update = async function () {

    if(ds_logisticsHeavyEquip.getRowCount() < 1){
        await $c.win.alert("수정할 장비정보를 먼저 조회해 주십시오.");
        ed_qryCntn.focus();
        return;
    }


    scwin.f_ContentsEnable();

    scwin.txt_updateYn = "1";   // 수정인경우
    scwin.txt_saveType = "1";  // 0:신규, 1:수정, 2:조회, 3:저장, 4:취소
    ica_eqChgDt.setValue(scwin.curDate);		// 장비변경일자

    $c.gus.cfDisableBtn([b_Update]);

}

//-------------------------------------------------------------------------
// 장비 등록, 수정 취소
//-------------------------------------------------------------------------
scwin.f_Cancel = function () {
    // 취소 확인


    if(ds_logisticsHeavyEquip.getRowPosition()>ds_logisticsHeavyEquip.getRowCount() || ds_logisticsHeavyEquip.getModifiedIndex().length > 0){
        ds_logisticsHeavyEquip.undoRow(ds_logisticsHeavyEquip.getRowPosition());
    }

    scwin.f_ContentsDisable();	

    $c.gus.cfDisableBtn([b_Cancel, btn_save]);	

    scwin.txt_saveType = "4";  // 0:신규, 1:수정, 2:조회, 3:저장, 4:취소
    ica_eqChgDt.setValue("");		// 장비변경일자  
}

//-------------------------------------------------------------------------
// 저장
//-------------------------------------------------------------------------
scwin.f_Save = async function () {

    scwin.txt_saveType = "3"; // 타입이 저장

    //변경한 데이터가 있는지 체크한다. 
    if(! ds_logisticsHeavyEquip.getModifiedIndex().length > 0){
        await $c.win.alert("변경된 사항이 없습니다.");
        return;
    }

    // 필수항목 체크
    if(! await $c.gus.cfValidate([ica_eqChgDt])){
        return ;
    }

    // 저장확인 
    if(await $c.win.confirm("저장하시겠습니까?") == true){
        scwin.pos_groupCode = ds_logisticsHeavyEquip.getRowPosition();

        sbm_saveLogisticsHeavyEquip.action ="/cm.bc.eq.eqmgnt.cmd.UpdateLogisticsHeavyEquipEquipmentInformationCMD.do";
        $c.sbm.execute(sbm_saveLogisticsHeavyEquip);
    }

};

//-------------------------------------------------------------------------
//목표유류소모율 소숫점 체크
//-------------------------------------------------------------------------

scwin.f_ChkCsmpRtStd = async function () {

    let vCompareValue = ed_csmpRtStd.getValue();

    let boolChk = cfValidateValue(vCompareValue, "minNumber=000.00&maxNumber=100.00& number=(5.2)");

    if(!boolChk){
        await $c.win.alert("목표유류소모율 입력이 잘못 입력되었습니다.");
        csmpRtStd.focus();
        return false;
    }
}

// function cfValidateValue(value, validExp) {
//     let valueValidExp = new covValueValidExp(validExp);

//     if (!valueValidExp.validate(value)) {
//         return false;
//     }
// return true;
// }


scwin.sbm_searchlogisticsHeavyEquip_submitdone = async function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) return;
    let rowCnt = ds_logisticsHeavyEquip.getRowCount()

    if (rowCnt == 0) {
        await $c.win.alert("조회된 데이터가 없습니다.");
        ed_qryCntn.focus();
        return;
    }

    if(scwin.vSysAdminYn== "0" && scwin.vUserHomeClsCd !="DS"){
        $c.gus.cfDisableAllBtn();
    }
    if(scwin.pos_groupCode > rowCnt){
        $c.gus.cfGoPrevPosition(gr_logisticsHeavyEquip, rowCnt-1);
    }else{
        $c.gus.cfGoPrevPosition(gr_logisticsHeavyEquip, scwin.pos_groupCode);
    }

    totalRows.setValue(rowCnt);
};


scwin.ed_csmpRtStd_onviewchange = async function (info) {
    const raw = info.newValue;
    if (!/^\d+(\.\d+)?$/.test(raw)) {
        await $c.win.alert("목표유류소모율 입력이 잘못 입력되었습니다.");
        ed_csmpRtStd.setValue("");
        ed_csmpRtStd.focus();
        return;
    }

    const val = parseFloat(info.newValue);
    if (val < 0 || val > 100) {
        await $c.win.alert("목표유류소모율 입력이 잘못 입력되었습니다.");
        ed_csmpRtStd.setValue("");
        ed_csmpRtStd.focus();
        return;
    }
};

